const TABS_ROOT = "data-bambi-tabs" as const;
const TABS_LIST = "data-bambi-tabs-list" as const;
const TABS_TRIGGER = "data-bambi-tabs-trigger" as const;
const TABS_CONTENT = "data-bambi-tabs-content" as const;
const TABS_VALUE = "data-value" as const;
const TABS_DEFAULT_VALUE = "data-default-value" as const;
const TABS_CONTROLLED = "data-controlled" as const;
const TABS_ORIENTATION = "data-orientation" as const;
const TABS_ACTIVATION_MODE = "data-activation-mode" as const;
const TABS_DISABLED = "data-disabled" as const;
const TABS_STATE = "data-state" as const;
const TABS_EVENT_VALUE_CHANGE = "bambi:value-change" as const;

export type TabsOrientation = "horizontal" | "vertical";
export type TabsActivationMode = "automatic" | "manual";

export interface TabsValueChangeDetail {
  value: string;
  previousValue: string | null;
  source: "click" | "keyboard";
}


interface RovingFocusOptions {
  
  orientation?: "horizontal" | "vertical" | "both";
  
  loop?: boolean;
  
  getItems: () => Element[];
  
  isDisabled?: (item: Element) => boolean;
  
  onFocus: (item: Element) => void;
  
  onActivate?: (item: Element) => void;
}

interface RovingFocus {
  destroy(): void;
}


function createRovingFocus(
  container: Element,
  options: RovingFocusOptions,
): RovingFocus {
  const abort = new AbortController();
  const { signal } = abort;
  const loop = options.loop ?? true;
  const orientation = options.orientation ?? "horizontal";

  const isHorizontal = orientation === "horizontal" || orientation === "both";
  const isVertical = orientation === "vertical" || orientation === "both";

  container.addEventListener(
    "keydown",
    (event: Event) => {
      const e = event as KeyboardEvent;
      const items = options
        .getItems()
        .filter((item) => !(options.isDisabled?.(item) ?? false));

      if (items.length === 0) return;

      const focused = items.findIndex((item) => item === document.activeElement);
      if (focused === -1) return;

      let next: Element | undefined;

      if (
        (isHorizontal && e.key === "ArrowRight") ||
        (isVertical && e.key === "ArrowDown")
      ) {
        e.preventDefault();
        const nextIndex = loop
          ? (focused + 1) % items.length
          : Math.min(focused + 1, items.length - 1);
        next = items[nextIndex];
      } else if (
        (isHorizontal && e.key === "ArrowLeft") ||
        (isVertical && e.key === "ArrowUp")
      ) {
        e.preventDefault();
        const prevIndex = loop
          ? (focused - 1 + items.length) % items.length
          : Math.max(focused - 1, 0);
        next = items[prevIndex];
      } else if (e.key === "Home") {
        e.preventDefault();
        next = items[0];
      } else if (e.key === "End") {
        e.preventDefault();
        next = items[items.length - 1];
      } else if ((e.key === "Enter" || e.key === " ") && options.onActivate) {
        e.preventDefault();
        const item = items[focused];
        if (item) options.onActivate(item);
        return;
      }

      if (next) options.onFocus(next);
    },
    { signal },
  );

  return {
    destroy() {
      abort.abort();
    },
  };
}


export interface TabsOptions {
  value?: string;
  defaultValue?: string;
  controlled?: boolean;
  orientation?: TabsOrientation;
  activationMode?: TabsActivationMode;
  disabled?: boolean;
}

function dispatchTabsEvent(element: Element, detail: TabsValueChangeDetail): void {
  element.dispatchEvent(
    new CustomEvent<TabsValueChangeDetail>(TABS_EVENT_VALUE_CHANGE, {
      bubbles: true,
      cancelable: false,
      composed: false,
      detail,
    }),
  );
}

class TabsBehavior implements BambiBehavior {
  private static _idCounter = 0;

  private readonly root: Element;
  private options: TabsOptions;
  private currentValue: string | null = null;
  private readonly _id: string;
  private readonly destroyAbort: AbortController;
  private bindAbort: AbortController;
  private rovingFocus: RovingFocus | null = null;

  constructor(root: Element, options: TabsOptions = {}) {
    this.root = root;
    this.options = options;
    this._id = root.id || `bambi-tabs-${++TabsBehavior._idCounter}`;
    this.destroyAbort = new AbortController();
    this.bindAbort = new AbortController();
  }

  sync(): void {
    this.bindAbort.abort();
    this.rovingFocus?.destroy();
    this.bindAbort = new AbortController();

    const orientation = (
      this.options.orientation ??
      getAttr(this.root, TABS_ORIENTATION, "horizontal")
    ) as TabsOrientation;

    setAttr(this.root, TABS_ORIENTATION, orientation);
    setAttr(
      this.root,
      TABS_ACTIVATION_MODE,
      this.options.activationMode ?? getAttr(this.root, TABS_ACTIVATION_MODE, "automatic"),
    );
    if (this.options.disabled !== undefined) {
      setAttr(this.root, TABS_DISABLED, this.options.disabled ? "true" : null);
    }
    for (const list of Array.from(this.root.querySelectorAll(`[${TABS_LIST}]`))) {
      list.setAttribute("role", "tablist");
      list.setAttribute("aria-orientation", orientation);
    }

    const value =
      (this.options.value ?? getAttr(this.root, TABS_VALUE, "")) ||
      (this.options.defaultValue ?? getAttr(this.root, TABS_DEFAULT_VALUE, "")) ||
      this.firstTriggerValue();
