      value,
      defaultValue,
      orientation,
      activationMode,
      disabled,
      controlled,
  });
});
</script>
<div
  bind:this={rootEl}
  {...props}
  data-bambi-tabs=""
  data-value={value}
  data-default-value={defaultValue}
  data-orientation={orientation}
  data-activation-mode={activationMode}
  data-disabled={disabled ? "true" : undefined}
  data-controlled={controlled ? "true" : undefined}
